parameters.jsCode:
const items = $input.all();

// Build lookup table
const currencies = {};

for (const item of items) {
  const source = item.json.source || item.json.title;

  for (const rate of (item.json.rates || [])) {
    const currency = rate.currency;

    if (!currencies[currency]) {
      currencies[currency] = {};
    }

    currencies[currency][source] = rate.kes_per_unit;
  }
}

let html = `
<h2>Forex Comparison Dashboard</h2>

<table border="1" cellpadding="5" cellspacing="0">
<tr>
<th>Currency</th>
<th>FloatRates</th>
<th>NCBA</th>
<th>ExchangeRate API</th>
</tr>
`;

for (const currency of Object.keys(currencies)) {
  html += `
  <tr>
    <td>${currency}</td>
    <td>${currencies[currency]["FloatRates Forex Rates"] || "-"}</td>
    <td>${currencies[currency]["NCBA Rates"] || "-"}</td>
    <td>${currencies[currency]["ExchangeRate API Forex Rates"] || "-"}</td>
  </tr>
  `;
}

html += `</table>`;

return [{
  json: {
    dashboard_html: html
  }
}];

return items.map(item => ({
  json: {
    headline: item.json.output.headline,
    newsletter_intro: item.json.output.newsletter_intro,
    market_outlook: item.json.output.market_outlook
  }
}));

const html = $json.data;

const regex = /data-currency="([^"]+)".*?buy-rate">([\d.]+)<.*?sell-rate">([\d.]+)</gs;

const rates = [];
let match;

while ((match = regex.exec(html)) !== null) {
  rates.push({
    currency: match[1],
    buy: parseFloat(match[2]),
    sell: parseFloat(match[3]),
  });
}

return [{
  json: {
    bank: "NCBA",
    rates
  }
}];

